# subprocessor_notification_watcher.py
# Polls Anthropic's subprocessor list endpoint and alerts on changes

import hashlib
import json
import smtplib
from email.mime.text import MIMEText
from pathlib import Path

SNAPSHOT_FILE = Path("data/anthropic_subprocessors_snapshot.json")
ANTHROPIC_SP_LIST_URL = "https://privacy.anthropic.com/api/subprocessors"  # illustrative

def fetch_sp_list(url: str) -> list[dict]:
    """Fetch current subprocessor list from Anthropic's privacy portal."""
    import urllib.request
    with urllib.request.urlopen(url, timeout=10) as response:
        return json.loads(response.read())

def hash_sp_list(sp_list: list[dict]) -> str:
    canonical = json.dumps(sorted(sp_list, key=lambda x: x.get("name", "")), sort_keys=True)
    return hashlib.sha256(canonical.encode()).hexdigest()

def detect_changes(old: list[dict], new: list[dict]) -> dict:
    old_names = {sp["name"] for sp in old}
    new_names = {sp["name"] for sp in new}
    return {
        "added":   [sp for sp in new if sp["name"] not in old_names],
        "removed": [sp for sp in old if sp["name"] not in new_names],
    }

def send_alert(changes: dict, to_addr: str):
    body_lines = ["Anthropic subprocessor list change detected:\n"]
    for added in changes["added"]:
        body_lines.append(f"ADDED:   {added['name']} — {added.get('purpose', 'unknown purpose')}")
    for removed in changes["removed"]:
        body_lines.append(f"REMOVED: {removed['name']}")
    body_lines.append("\nAction required: complete subprocessor review within 15 days.")
    msg = MIMEText("\n".join(body_lines))
    msg["Subject"] = "Action Required: Anthropic Subprocessor Change Detected"
    msg["From"] = "compliance-bot@yourcompany.com"
    msg["To"] = to_addr
    with smtplib.SMTP("localhost") as s:
        s.send_message(msg)

def run_check():
    current = fetch_sp_list(ANTHROPIC_SP_LIST_URL)
    if SNAPSHOT_FILE.exists():
        previous = json.loads(SNAPSHOT_FILE.read_text())
        changes = detect_changes(previous, current)
        if changes["added"] or changes["removed"]:
            send_alert(changes, "privacy-team@yourcompany.com")
            print(f"ALERT sent: {len(changes['added'])} added, {len(changes['removed'])} removed")
        else:
            print("No changes detected")
    else:
        print("First run — snapshot saved")
    SNAPSHOT_FILE.write_text(json.dumps(current, indent=2))

if __name__ == "__main__":
    run_check()
